677: <span class="c-cm">// 제곱 거리(sqrMagnitude) 사용으로 sqrt 연산 제거 최적화</span>
678: <span class="c-kw">private void</span> <span class="c-fn">SearchClosestBetter</span>(<span class="c-ty">FileGrid</span> candidate, <span class="c-ty">Vector2</span> worldPos, <span class="c-kw">ref float</span> bestDistSqr, <span class="c-kw">ref FileGrid</span> bestGrid)
