330: 
331: #### 3.1.1 쿼리 스탬프를 활용한 중복 검사 방지
332: 크기가 큰 오브젝트는 여러 개의 그리드 셀에 걸쳐 존재할 수 있습니다. 뷰포트 영역 내의 셀들을 순회할 때 동일한 객체가 여러 번 쿼리되는 것을 막기 위해 **쿼리 스탬프(Query Stamp)** 기법을 도입했습니다. 쿼리가 발생할 때마다 전역 스탬프 값을 1씩 증가시키고, 이미 검사한 객체에 스탬프를 남겨 불필요한 중복 연산을 완전히 제거했습니다.
333: 
334: <details class="pf-details" markdown="1">
335: <summary>코드 보기: ObjectManager.cpp - O(1) 인덱싱 및 가시 객체 추출</summary>
336: 
337: ```cpp
338: // ObjectManager.cpp - 뷰포트 기반 공간 분할 쿼리
339: void ObjectManager::QueryObjectsInRectArea(const Gdiplus::RectF& rectArea, std::vector<GameObject*>& targetOutObjects)
340: {
341:     // 월드 좌표를 셀 크기로 나누어 O(1)로 배열 인덱스 획득
342:     int startX = (int)floor(rectArea.X / GRID_CELL_SIZE);
343:     int startY = (int)floor(rectArea.Y / GRID_CELL_SIZE);
344:     int endX = (int)ceil((rectArea.X + rectArea.Width) / GRID_CELL_SIZE) - 1;
345:     int endY = (int)ceil((rectArea.Y + rectArea.Height) / GRID_CELL_SIZE) - 1;
346:     
347:     // ... 인덱스 클램핑 생략 ...
348: 
349:     // 매 쿼리마다 전역 스탬프 갱신
350:     if (++m_spatialQueryStamp == 0) m_spatialQueryStamp = 1;
351: 
352:     for (int y = startY; y <= endY; ++y) {
353:         for (int x = startX; x <= endX; ++x) {
354:             for (auto* obj : m_spatialGrid[x][y]) {
355:                 // 이미 이번 프레임(쿼리)에서 처리된 객체는 O(1) 스킵
356:                 if (obj->GetLastSpatialQueryStamp() == m_spatialQueryStamp) continue;
357:                 obj->SetLastSpatialQueryStamp(m_spatialQueryStamp);
358: 
359:                 if (!obj->IsEnabled() || obj->IsDead()) continue;
360: 
361:                 // 해당 셀에 속한 객체만 AABB 교차 정밀 검사 수행
362:                 if (rectArea.IntersectsWith(obj->GetBounds())) {
363:                     targetOutObjects.push_back(obj);
364:                 }
365:             }
366:         }
367:     }
368: }
369: ```
370: </details>
371: 
372: #### 3.1.2 동적 오브젝트의 그리드 이동 처리
373: 플레이어나 몬스터처럼 실시간으로 좌표가 변하는 동적 객체들은 이동할 때마다 자신이 속한 그리드 셀을 갱신해야 합니다. `UpdateObjectGrid` 메서드는 객체의 위치가 셀의 경계를 넘어갔을 때만 이전 벡터 배열에서 객체를 `erase`하고 새 배열에 `push_back`하여 갱신 비용을 최소화합니다.
374: 
375: <details class="pf-details" markdown="1">
376: <summary>코드 보기: ObjectManager.cpp - 동적 그리드 갱신</summary>
377: 
378: ```cpp
379: // ObjectManager.cpp - 객체 이동 시 그리드 셀 갱신
380: void ObjectManager::UpdateObjectGrid(GameObject* pObj)
381: {
382:     if (!pObj || pObj->GetType() == GO_TYPE_UI) return;
383: 
384:     int oldX = pObj->GetGridCellX();
385:     int oldY = pObj->GetGridCellY();
386: 
387:     Gdiplus::RectF bounds = pObj->GetBounds();
388:     int newX = (std::max)(0, (std::min)(GRID_WIDTH - 1, (int)floor((bounds.X + bounds.Width * 0.5f) / GRID_CELL_SIZE)));
389:     int newY = (std::max)(0, (std::min)(GRID_HEIGHT - 1, (int)floor((bounds.Y + bounds.Height * 0.5f) / GRID_CELL_SIZE)));
390: 
391:     // 속한 셀이 변경된 경우에만 이동 처리
392:     if (oldX == newX && oldY == newY) return;
393: 
394:     if (oldX >= 0 && oldX < GRID_WIDTH && oldY >= 0 && oldY < GRID_HEIGHT) {
395:         std::vector<GameObject*>& cell = m_spatialGrid[oldX][oldY];
396:         cell.erase(std::remove(cell.begin(), cell.end(), pObj), cell.end());
397:     }
398: 
399:     m_spatialGrid[newX][newY].push_back(pObj);
400:     pObj->SetGridCell(newX, newY);
401: }
402: ```
403: </details>
